ALGORITHM Producer_Consumer
INPUT: Buffer of size N, producing/consuming items
OUTPUT: Successfully produced and consumed items

// Shared variables
CONSTANT BUFFER_SIZE = N
ARRAY buffer[BUFFER_SIZE]
INTEGER in = 0 // points to next free position
INTEGER out = 0 // points to first full position

// ========== PRODUCER PROCESS ==========
PROCEDURE Producer
WHILE true DO
 item = produce_item() // Generate a new item

 // Wait if buffer is full
 // Buffer is full when next position equals out position
 WHILE ((in + 1) MOD BUFFER_SIZE) = out DO
 // Busy wait - do nothing
 END WHILE

 buffer[in] = item // Place item in buffer
 in = (in + 1) MOD BUFFER_SIZE // Move to next position (circular)
END WHILE

// ========== CONSUMER PROCESS ==========
PROCEDURE Consumer
WHILE true DO
 // Wait if buffer is empty
 // Buffer is empty when in equals out
 WHILE in = out DO
 // Busy wait - do nothing
 END WHILE

 item = buffer[out] // Remove item from buffer
 out = (out + 1) MOD BUFFER_SIZE // Move to next position (circular)

 consume_item(item) // Process the consumed item
END WHILE

// ========== NOTES ==========
// 1. Buffer can hold at most N-1 items (one slot wasted)
// 2. This is required to distinguish full from empty state
// 3. Uses circular array for efficient memory usage
// 4. Both processes must be synchronized to avoid race conditions

/*
 * Producer-Consumer Problem using Shared Memory IPC
 * Demonstrates: Shared Memory + Semaphores for synchronization
 * 
 * Compile: gcc -o producer_consumer producer_consumer.c -lpthread -lrt
 * Run: ./producer_consumer
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/ipc.h>
#include <sys/shm.h>
#include <sys/sem.h>
#include <sys/wait.h>
#include <time.h>

/* Buffer configuration */
#define BUFFER_SIZE 5
#define NUM_ITEMS 10

/* Shared buffer structure */
typedef struct {
 char buffer[BUFFER_SIZE][100]; // Circular buffer for items
 int in; // Next free position (producer)
 int out; // First full position (consumer)
 int count; // Number of items in buffer
} SharedBuffer;

/* Semaphore operations - POSIX unnamed semaphores not used 
 * to keep it simple; using SysV semaphores instead */

/* Union for semctl operations */
union semun {
 int val;
 struct semid_ds *buf;
 unsigned short *array;
} sem_arg;

/* Semaphore IDs */
int sem_mutex; // Mutual exclusion for shared buffer
int sem_empty; // Count of empty slots
int sem_full; // Count of full slots

/* Shared memory ID and pointer */
int shm_id;
SharedBuffer *shm_ptr;

/* Initialize shared memory and semaphores */
void init_ipc() {
 /* Create shared memory segment */
 shm_id = shmget(IPC_PRIVATE, sizeof(SharedBuffer), IPC_CREAT | 0666);
 if (shm_id < 0) {
 perror("shmget failed");
 exit(1);
 }

 /* Attach shared memory */
 shm_ptr = (SharedBuffer *)shmat(shm_id, NULL, 0);
 if (shm_ptr == (SharedBuffer *)-1) {
 perror("shmat failed");
 exit(1);
 }

 /* Initialize buffer */
 shm_ptr->in = 0;
 shm_ptr->out = 0;
 shm_ptr->count = 0;

 /* Create semaphores */
 sem_mutex = semget(IPC_PRIVATE, 1, IPC_CREAT | 0666);
 sem_empty = semget(IPC_PRIVATE, 1, IPC_CREAT | 0666);
 sem_full = semget(IPC_PRIVATE, 1, IPC_CREAT | 0666);

 /* Initialize semaphore values */
 sem_arg.val = 1;
 semctl(sem_mutex, 0, SETVAL, sem_arg); // Mutex = 1 (unlocked)

 sem_arg.val = BUFFER_SIZE;
 semctl(sem_empty, 0, SETVAL, sem_arg); // Empty slots = BUFFER_SIZE

 sem_arg.val = 0;
 semctl(sem_full, 0, SETVAL, sem_arg); // Full slots = 0
}

/* Semaphore wait (P operation) */
void sem_wait(int sem_id) {
 struct sembuf sb;
 sb.sem_num = 0;
 sb.sem_op = -1; // Decrement
 sb.sem_flg = 0;

 if (semop(sem_id, &sb, 1) < 0) {
 perror("sem_wait failed");
 exit(1);
 }
}

/* Semaphore signal (V operation) */
void sem_signal(int sem_id) {
 struct sembuf sb;
 sb.sem_num = 0;
 sb.sem_op = 1; // Increment
 sb.sem_flg = 0;

 if (semop(sem_id, &sb, 1) < 0) {
 perror("sem_signal failed");
 exit(1);
 }
}

/* Producer process */
void producer() {
 printf("[PRODUCER] Starting (PID: %d)\n", getpid());

 for (int i = 0; i < NUM_ITEMS; i++) {
 /* Wait for empty slot */
 sem_wait(sem_empty);

 /* Enter critical section */
 sem_wait(sem_mutex);

 /* Produce item and add to buffer */
 sprintf(shm_ptr->buffer[shm_ptr->in], "Item-%d", i);
 printf("[PRODUCER] Produced: %s | Buffer count: %d\n", 
 shm_ptr->buffer[shm_ptr->in], shm_ptr->count + 1);

 /* Update in pointer (circular) */
 shm_ptr->in = (shm_ptr->in + 1) % BUFFER_SIZE;
 shm_ptr->count++;

 /* Exit critical section */
 sem_signal(sem_mutex);

 /* Signal that item is available */
 sem_signal(sem_full);

 /* Simulate production delay */
 usleep(random() % 300000);
 }

 printf("[PRODUCER] Finished producing %d items\n", NUM_ITEMS);
}

/* Consumer process */
void consumer() {
 printf("[CONSUMER] Starting (PID: %d)\n", getpid());

 for (int i = 0; i < NUM_ITEMS; i++) {
 /* Wait for item to be available */
 sem_wait(sem_full);

 /* Enter critical section */
 sem_wait(sem_mutex);

 /* Remove item from buffer */
 char item[100];
 strcpy(item, shm_ptr->buffer[shm_ptr->out]);
 printf("[CONSUMER] Consumed: %s | Buffer count: %d\n", 
 item, shm_ptr->count - 1);

 /* Update out pointer (circular) */
 shm_ptr->out = (shm_ptr->out + 1) % BUFFER_SIZE;
 shm_ptr->count--;

 /* Exit critical section */
 sem_signal(sem_mutex);

 /* Signal that slot is now empty */
 sem_signal(sem_empty);

 /* Simulate consumption delay */
 usleep(random() % 400000);
 }

 printf("[CONSUMER] Finished consuming %d items\n", NUM_ITEMS);
}

/* Cleanup IPC resources */
void cleanup() {
 /* Detach shared memory */
 shmdt(shm_ptr);

 /* Remove shared memory segment */
 shmctl(shm_id, IPC_RMID, NULL);

 /* Remove semaphores */
 semctl(sem_mutex, 0, IPC_RMID);
 semctl(sem_empty, 0, IPC_RMID);
 semctl(sem_full, 0, IPC_RMID);

 printf("\n[SYSTEM] IPC resources cleaned up\n");
}

int main() {
 pid_t pid;

 printf("============================================================\n");
 printf("IPC Demo: Shared Memory Producer-Consumer\n");
 printf("============================================================\n\n");

 /* Seed random number generator */
 srand(time(NULL));

 /* Initialize IPC mechanisms */
 init_ipc();

 /* Fork consumer process */
 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 cleanup();
 exit(1);
 }

 if (pid == 0) {
 /* Child process - Consumer */
 consumer();
 exit(0);
 }

 /* Parent process - Producer */
 producer();

 /* Wait for child to finish */
 wait(NULL);

 /* Cleanup */
 cleanup();

 printf("\n============================================================\n");
 printf("IPC Complete!\n");
 printf("============================================================\n");

 return 0;
}

/*
 * =====================================================================
 * Explanation of IPC Mechanisms Used:
 * 
 * 1. SHARED MEMORY:
 * - shmget() creates a shared memory segment
 * - shmat() attaches it to process's address space
 * - Both processes can now read/write to the same buffer
 * - This is the SHARED MEMORY IPC model
 * 
 * 2. SEMAPHORES (for synchronization):
 * - sem_empty: Counts empty slots (initially BUFFER_SIZE)
 * - sem_full: Counts full slots (initially 0)
 * - sem_mutex: Ensures mutual exclusion (only one process
 * can access buffer at a time)
 * 
 * 3. SYNCHRONIZATION PATTERN:
 * Producer: wait(empty) → wait(mutex) → write → signal(mutex) → signal(full)
 * Consumer: wait(full) → wait(mutex) → read → signal(mutex) → signal(empty)
 * 
 * This demonstrates the SHARED MEMORY model of IPC where:
 * - Processes share a common memory region
 * - OS sets up the shared memory segment
 * - Processes are responsible for synchronization
 * =====================================================================
 */

/*
 * Message Passing IPC using POSIX Message Queues
 * Demonstrates the Message Passing model of IPC
 * 
 * Compile: gcc -o msg_queue msg_queue.c -lrt
 * Run: ./msg_queue
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <mqueue.h>
#include <signal.h>
#include <time.h>
#include <errno.h>

/* Message queue configuration */
#define QUEUE_NAME "/ipc_demo_queue"
#define MAX_MSG_SIZE 256
#define MAX_MESSAGES 10

/* Message structure */
typedef struct {
 int msg_type; // Message type (for selective receiving)
 int sender_pid; // PID of sender process
 char content[MAX_MSG_SIZE]; // Message content
} Message;

/* Message queue descriptor */
mqd_t mq;

/* Signal handler for cleanup */
void cleanup(int sig) {
 if (mq != -1) {
 mq_close(mq);
 mq_unlink(QUEUE_NAME);
 }
 exit(0);
}

/* Sender process - sends messages to the queue */
void sender_process() {
 printf("[SENDER] Starting (PID: %d)\n", getpid());

 /* Message to send */
 Message msg;
 msg.msg_type = 1; // Message type 1
 msg.sender_pid = getpid();

 /* Open message queue for sending */
 mq = mq_open(QUEUE_NAME, O_WRONLY);
 if (mq == (mqd_t)-1) {
 perror("[SENDER] mq_open failed");
 exit(1);
 }

 /* Send messages */
 for (int i = 1; i <= 5; i++) {
 snprintf(msg.content, MAX_MSG_SIZE, 
 "Message #%d from producer - Data: %d", 
 i, i * 100);

 /* Send message (blocks if queue is full) */
 if (mq_send(mq, (char *)&msg, sizeof(Message), 0) == -1) {
 perror("[SENDER] mq_send failed");
 continue;
 }

 printf("[SENDER] Sent: %s\n", msg.content);
 usleep(random() % 500000); // Simulate delay
 }

 /* Send termination message */
 msg.msg_type = 99; // Special type for termination
 snprintf(msg.content, MAX_MSG_SIZE, "TERMINATE");
 mq_send(mq, (char *)&msg, sizeof(Message), 0);

 printf("[SENDER] Sent TERMINATE signal\n");

 mq_close(mq);
 printf("[SENDER] Finished\n");
 exit(0);
}

/* Receiver process - receives messages from the queue */
void receiver_process() {
 printf("[RECEIVER] Starting (PID: %d)\n", getpid());

 /* Open message queue for receiving */
 mq = mq_open(QUEUE_NAME, O_RDONLY);
 if (mq == (mqd_t)-1) {
 perror("[RECEIVER] mq_open failed");
 exit(1);
 }

 /* Receive messages */
 Message msg;
 unsigned int prio;

 while (1) {
 /* Receive message (blocks if queue is empty) */
 ssize_t bytes_received = mq_receive(mq, (char *)&msg, 
 sizeof(Message), &prio);

 if (bytes_received == -1) {
 perror("[RECEIVER] mq_receive failed");
 continue;
 }

 printf("[RECEIVER] Received (type=%d, prio=%u): %s\n", 
 msg.msg_type, prio, msg.content);

 /* Check for termination message */
 if (msg.msg_type == 99) {
 printf("[RECEIVER] Termination signal received\n");
 break;
 }
 }

 mq_close(mq);
 printf("[RECEIVER] Finished\n");
 exit(0);
}

int main() {
 pid_t pid;
 struct mq_attr attr;

 printf("============================================================\n");
 printf("IPC Demo: Message Passing using POSIX Message Queues\n");
 printf("============================================================\n\n");

 /* Set up signal handler for cleanup */
 signal(SIGINT, cleanup);

 /* Seed random */
 srand(time(NULL));

 /* Set message queue attributes */
 attr.mq_flags = 0; // Blocking mode
 attr.mq_maxmsg = MAX_MESSAGES; // Maximum messages in queue
 attr.mq_msgsize = sizeof(Message); // Maximum message size
 attr.mq_curmsgs = 0; // Current messages (initially 0)

 /* Create message queue */
 mq = mq_open(QUEUE_NAME, O_CREAT | O_EXCL | O_RDWR, 0666, &attr);

 if (mq == (mqd_t)-1) {
 /* Queue might exist, try to unlink and recreate */
 mq_unlink(QUEUE_NAME);
 mq = mq_open(QUEUE_NAME, O_CREAT | O_EXCL | O_RDWR, 0666, &attr);

 if (mq == (mqd_t)-1) {
 perror("mq_open (create) failed");
 exit(1);
 }
 }

 printf("[SYSTEM] Message queue created: %s\n", QUEUE_NAME);
 printf("[SYSTEM] Max messages: %ld, Message size: %ld\n\n",
 attr.mq_maxmsg, attr.mq_msgsize);

 /* Fork receiver (child) process */
 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 mq_close(mq);
 mq_unlink(QUEUE_NAME);
 exit(1);
 }

 if (pid == 0) {
 /* Child - Receiver process */
 mq_close(mq); // Close parent's copy
 receiver_process();
 }

 /* Parent - Sender process */
 sender_process();

 /* Wait for child to finish */
 wait(NULL);

 /* Cleanup */
 mq_close(mq);
 mq_unlink(QUEUE_NAME);

 printf("\n============================================================\n");
 printf("IPC Complete! Message queue cleaned up.\n");
 printf("============================================================\n");

 return 0;
}

/*
 * =====================================================================
 * Explanation of Message Passing IPC:
 * 
 * 1. POSIX MESSAGE QUEUES:
 * - mq_open() creates or opens a message queue
 * - mq_send() adds message to queue (blocks if full)
 * - mq_receive() retrieves message (blocks if empty)
 * - Messages have type and priority
 * 
 * 2. KEY CHARACTERISTICS:
 * - Processes do NOT share memory address space
 * - Communication goes through kernel-managed queue
 * - Messages are copied from sender to receiver via kernel
 * - Provides asynchronous communication (non-blocking)
 * - Supports message priorities
 * 
 * 3. DIFFERENCE FROM SHARED MEMORY:
 * + No explicit synchronization needed (kernel handles it)
 * + Better for distributed systems
 * - Higher overhead (message copying)
 * - Limited message size
 * 
 * 4. USE CASES:
 * - Inter-process communication on same machine
 * - Client-server communication
 * - Event-driven systems
 * - Microservices messaging
 * =====================================================================
 */
